var f = this;
if ($func.trim(f.getItemValue('loai_ct')) == '1') {
  var c = 'd52', d1 = f.getItemValue('ngay_lct'), g = f.getItem(c)._controlBehavior;
  for (var row = 1; row <= g._rowCount; row ++) {
    var d2 = g._getItemValue(row, g._getColumnOrder('ngay_hd'));
    if (d1 != null && d2 != null && d1 < d2) {
      g._errorObject = g._getItem(row, g._getColumnOrder('ngay_hd'));
      errorMessage = (f._language == 'v' ? 'Trường <span class="Highlight">ngày hóa đơn</span> phải nhỏ hơn <span class="Highlight">ngày lập chứng từ</span>.' : '<span class="Highlight">Invoice date</span> must be less than <span class="Highlight">voucher date</span>.');
      $func.hideWait(f.get_id());
      f.focus(c);
      f._checked = false;
      $message.show(errorMessage, String.format('$find(\'{0}\')._errorObject.focus()', g.get_id()));
      break;
    }
  }
}
