function init$Voucher$(f) {initialize(f, null, null, 'loai_ct', 'status');}
/* </flatten> */
function active$Voucher$(f) {&ScriptActiveVoucher;
  f.getItem('d52')._controlBehavior.add_onRender(on$Voucher$GridRender);
  f._tabContainer.add_activeTabChanged(onChange$Voucher$Tab);
  f._tabContainer._loaded = true;
 &APVSetReadOnlyFields;
      &APVHandleStatus;
      &VoucherLogHandleStatus;
      &ListCreate;
      &PostCreate;

}
function scatter$Voucher$(f) {
&ScriptScatterVoucher;
      &APVSetReadOnlyFields;
      &VoucherLogHandleStatus;

}
function close$Voucher$(f) {&ScriptCloseVoucher;
  try {f.getItem('d52')._controlBehavior.remove_onRender(on$Voucher$GridRender);} catch (ex) {}
  if (f._tabContainer) try {f._tabContainer.remove_activeTabChanged(onChange$Voucher$Tab);} catch (ex) {}
  &ListDispose;
  &PostDispose;
}
function on$Voucher$ExecuteCommand(sender, e) {
  var action = e.type.Action, f = sender, g = f.getItem('d52')._controlBehavior;
  switch (action) {
    case 'Shown':
      &ListShown;
      &PostShown;
      break;
    case 'Save':
      set$Voucher$EmptyControlField(f, g, 'so_hd', '1');
      break;
    case 'Gather':
      g.setSequenceNumber('line_nbr');
      g.setContinuance('stt_rec0');
      break;
    case 'Explore':
      &APVAddStatus;
      &VoucherLogHandleStatusExplore;
      break;
    default:
      break;
  }
}
/* <flatten type="Javascript"> */
function on$Voucher$GridRender(sender, eventArgs) { set$Voucher$GridColumns(eventArgs.grid); }
/* </flatten> */
      &ScriptVoucherNumber;

objectBehavior$Voucher$Currency = {
&ScriptCurrency;
  create: function(f) {
    var d = f.getItem('ngay_lct'), p = f.getItem('ngay_ct'), c = f.getItem('ma_nt'), r = f.getItem('ty_gia'), g = f.getItem('d52')._controlBehavior;
    var v = f._currencyBehavior = $create(FastBusiness.AjaxControlExtender.Currency, {id: f._id + '_currencyBehavior', currencyDate: d, referenceDate: p, exchangeRate: r, form: f, baseCurrency: f._baseCurrency}, null, null, c);
    v.set_currencyFields('t_tien_nt,t_thue_nt,t_tt_nt:t_tien,t_thue,t_tt');
    v.addGridFields(g, 'tien_nt, thue_nt, tt_nt:tien, thue, tt');

    v.addTotalFields(g, [['t_tien_nt', 'tien_nt'], ['t_thue_nt', 'thue_nt'], ['t_tien', 'tien'], ['t_thue', 'thue']]);
    v.set_referenceFields(null);
    v.set_executeExpression(['[t_tt_nt]:=[t_tien_nt]+[t_thue_nt]', '[t_tt]:=[t_tien]+[t_thue]']);
    v.init();
    v.setFormLayout(0);
    this.init(f);
  },
  onCurrencyChanged: function(sender, e) {
    this.onCurrencySelected(sender, e);
    var c = e.object, f = c._currency.parentForm;
    if (c._baseCurrency == e.type) {
      c._exchangeRate._controlBehavior._set_number(1);
      c.onExchangeRateChanged();
    }
    else {
      var d = f.getItemValue('ngay_lct');
      if (d) f.request('GetExchangeRate', 'GetExchangeRate', ['ma_nt', 'ngay_lct']);
    }
    set$Voucher$DependOnVoucherType(f);
  },
  onDateChanged: function(sender, e) {
    var c = e.object, f = c._currency.parentForm;
    if (e.type && (c._currency.value != c._baseCurrency)) f.request('GetExchangeRate', 'DateChanged', ['ma_nt', 'ngay_lct']);
  },
  onCurrencySelected: function(sender, e) {
    if (e.object._baseCurrency == e.type){
      e.object._form.focusWhenTabChanged(['d52', 'nguoi_duyet'&ListTabChange;&PostTabChange;]);
      &PostCurrencySelected;
    }
  }
}

function onChange$Voucher$Tab(sender, e) {
  sender.parentForm.focusWhenTabChanged(['d52', 'nguoi_duyet'&ListTabChange;&PostTabChange;]);
  &PostTabFocus;
}
/* <flatten type="Javascript"> */
function onChange$Voucher$Customer(o) {
  var f = o.parentForm, v = $func.trim(f.getItemValue('loai_ct'));
  f.request('Customer', 'Customer', ['ma_kh'], o);
  if (v == 1) set$Voucher$Customer$EmptyInvoice(f.getItem('d52')._controlBehavior, 'so_hd', 'tk_no');
}
function onChange$Voucher$Date(o) {
  var f = o.parentForm; v = $func.trim(f.getItemValue('loai_ct')), g = f.getItem('d52');
  if (v == 1 && g && g._activeCell) set$Voucher$Customer$KeyFilter(g._controlBehavior, 'so_hd');
}
function onChange$Voucher$Memo(o) {
  var g = o.parentForm.getItem('d52')._controlBehavior;
  if ((o.parentForm._action == 'New') && (g._rowCount > 0) && (g._getItemValue(1, g._getColumnOrder('dien_giai')) == ''))
    g._getItem(1, g._getColumnOrder('dien_giai')).value = o.value;
}
function onChange$Voucher$VoucherType(o) {set$Voucher$DependOnVoucherType(o.parentForm);}
function onchange$Item$(o) {
  if (o.value == '2') {
    var f = o.parentForm, g = f.getItem('d52')._controlBehavior, r = g._rowCount, c = 'tk_no';
    if (r == 1 && g._getItemValue(1, g._getColumnOrder(c)) == '') {
      var i = g._getItem(r, 1);
      i.row = r;
      g.setItemGridBehavior(i, [[c, f.getItemValue('tk_ex'), f.getItemValue('ten_tk_ex'), false]]);
    }
  }
}
/* </flatten> */
function on$Voucher$ResponseComplete(sender, e) {
  var f = e.object, context = e.type.Context, result = e.type.Result;
  switch (context){
    case 'Loading':
      &VoucherNumberLoading;
      &APVSetVoucherDefaultValue;
      break;
    case 'Scattering':
      &VoucherNumberScattering;
      &APVSetVoucherDefaultValue;
      &ListScattering;
      &PostScattering;
      set$Voucher$DependOnVoucherType(f);
      break;

      &VoucherNumberReading;
      &CurrencyResponse;
      &ListResponseTicket;
    case 'Navigating':
      &ListRefresh;
      &PostRefresh;
      break;
    case 'Customer':
      f.setItemControlBehavior('dia_chi', result[0].Value, null, true);
      f.setItemValues('tk_ex, ten_tk_ex', [result[1].Value, result[2].Value]);
      onchange$Item$(f.getItem('loai_ct'));

      f.live(f.getItem('dia_chi'));
      break;
    default:
      break;
  }
}
/* <flatten type="Javascript"> */
function set$Voucher$DependOnVoucherType(f) {
  var g = f.getItem('d52')._controlBehavior;
  set$Voucher$GridColumns(g);
}

function set$Voucher$GridColumns(g) {
  var f = g.get_element().parentForm, v = f.getItemValue('loai_ct'), a = ['so_hd', 'ngay_hd', 'tien_hd_nt', 'da_tt_nt', 'cl_nt', 'ma_nt_i', 'tt_qd'];
  var tax = ['ma_thue', 'thue_suat', 'tk_thue', 'thue_nt', 'thue', 'tt_nt', 'tt', 'ma_kh2'];
  var taxEx = ['thue', 'tt'];
  var fc = (f.getItem('ma_nt').value == f._baseCurrency);
  g._suspendLayout();
  for (var i = 0; i < a.length; i++) {
    g._setColumnVisible(g._getColumnOrder($func.trim(a[i])), (v == 1));
  }

  for (var j = 0; j < tax.length; j++) {
    g._setColumnVisible(g._getColumnOrder($func.trim(tax[j])), (v == 2));
  }

  for (var k = 0; k < taxEx.length; k++) {
    if ((v == 2) && fc) {g._setColumnVisible(g._getColumnOrder($func.trim(taxEx[k])), false); }
  }
  g._setColumnVisible(g._getColumnOrder('ten_tk_no%l'), (v != 1));
  g._resumeLayout();
}
function visible$Voucher$ExchangeRateColumn(f) {
  var v = f.getItemValue('loai_ct');
  return ((v == 0) && f.getItem('ma_nt').value != f._baseCurrency);
}

function set$Voucher$Customer$EmptyInvoice(g, c, a) {
  set$Voucher$Customer$KeyFilter(g, c);
  var l = g._getColumnOrder(c);
  for (var i = 0; i < g._rowCount; i++) {
    var o = g._getItem(i + 1, l);
    if (!o.row) o.value = '';
      else {
        o.row = i + 1;
        g.setItemGridBehavior(o, [['so_hd', '', ''], [a, '', '']]);
      }
  }
}
function set$Voucher$Customer$KeyFilter(g, c) {
  var o = g._activeCell, l = g._getColumnOrder(c);
  if (l == g._activeColumn) {
    if (o._controlBehavior) {
      var fields = g._fields, field = g._fields[l - 1], r = o.row, id = g.get_id();
      if (field.ItemKeyFilter) o._controlBehavior.set_completionKeyFilter($func.completionFilter(o, fields, field.ItemKeyFilter, r, id));
      if (field.ItemCheckFilter) o._controlBehavior.set_completionCheckFilter($func.completionFilter(o, fields, field.ItemCheckFilter, r, id));
    }
  }
}
function set$Voucher$EmptyControlField(f, g, c, t) {
  if (f.getItemValue('loai_ct') == t) return;
  for (var i = 0; i < g._rowCount; i++) {
    var o = g._getItem(i + 1, g._getColumnOrder(c));
    if (!o.row) o.value = '';
      else {
        o.row = i + 1;
        g.setItemGridBehavior(o, [[c, '', '']]);
      }
  }
}
/* </flatten> */
